mapper.select:
SELECT
FROM M_STOCK
AND STOCK_CODE = #{stockCode}
AND STOCK_NAME LIKE CONCAT('%', #{stockName}, '%')
AND TYPE_CODE = #{typeCode}
AND TYPE_NAME LIKE CONCAT('%', #{typeName}, '%')
AND MARKET = #{market}
AND CAST(REPLACE(REPLACE(REPLACE(STOCK_PRICE, ',', ''), '，', ''), ' ', '') AS DECIMAL(18,2)) >= #{stockPriceFrom}
AND CAST(REPLACE(REPLACE(REPLACE(STOCK_PRICE, ',', ''), '，', ''), ' ', '') AS DECIMAL(18,2)) <= #{stockPriceTo}
AND ( TEKUSYOKU LIKE CONCAT('%', #{freeWord}, '%') OR RENKETU_ZIGYO LIKE CONCAT('%', #{freeWord}, '%') OR SUPPLIER LIKE CONCAT('%', #{freeWord}, '%') OR SALES_DESTINATION LIKE CONCAT('%', #{freeWord}, '%') )
AND DEL_FLG = '0'
ORDER BY
STOCK_CODE TYPE_CODE MARKET CAST(REPLACE(REPLACE(REPLACE(STOCK_PRICE, ',', ''), '，', ''), ' ', '') AS DECIMAL(18,2)) ID
ASC DESC
LIMIT #{limit} OFFSET #{offset}

SELECT
    COUNT(1)
FROM M_STOCK


        AND STOCK_CODE = #{stockCode}


        AND STOCK_NAME LIKE CONCAT('%', #{stockName}, '%')


        AND TYPE_CODE = #{typeCode}


        AND TYPE_NAME LIKE CONCAT('%', #{typeName}, '%')


        AND MARKET = #{market}


        AND CAST(REPLACE(REPLACE(REPLACE(STOCK_PRICE, ',', ''), '，', ''), ' ', '') AS DECIMAL(18,2)) >= #{stockPriceFrom}


        AND CAST(REPLACE(REPLACE(REPLACE(STOCK_PRICE, ',', ''), '，', ''), ' ', '') AS DECIMAL(18,2)) <= #{stockPriceTo}


        AND (
            TEKUSYOKU LIKE CONCAT('%', #{freeWord}, '%')
            OR RENKETU_ZIGYO LIKE CONCAT('%', #{freeWord}, '%')
            OR SUPPLIER LIKE CONCAT('%', #{freeWord}, '%')
            OR SALES_DESTINATION LIKE CONCAT('%', #{freeWord}, '%')
        )

    AND DEL_FLG = '0'

SELECT ID, STOCK_CODE, STOCK_NAME, MARKET FROM M_STOCK
DEL_FLG = '0'
AND ( STOCK_CODE LIKE CONCAT('%', #{keyword}, '%') OR STOCK_NAME LIKE CONCAT('%', #{keyword}, '%') )
AND MARKET = #{market}
ORDER BY STOCK_CODE ASC LIMIT #{limit}

mapper.update:
UPDATE M_STOCK
SET
    DEL_FLG = #{delFlg}
WHERE ID = #{id}

UPDATE M_STOCK SET DEL_FLG = '1' WHERE DEL_FLG = '0'
AND STOCK_CODE NOT IN
#{code}
